const { user: { id }, tags: [firstTag] } = data;

// --- Proxy ---
const proxy = new Proxy(target, {
  get(obj, prop) { return prop in obj ? obj[prop] : 'Not Found'; }
});

// --- Generators ---
function* idGenerator() {
  let id = 1;
  while(true) yield id++;
}

// --- Symbols ---
const HIDDEN = Symbol('private');
obj[HIDDEN] = 'secret';

codeExample1.code:
const user = { age: 25 };

const validator = {
  set(obj, prop, value) {
    if (prop === 'age') {
      if (typeof value !== 'number') throw new TypeError('Age must be a number');
      if (value < 0) throw new RangeError('Age cannot be negative');
    }
    obj[prop] = value;
    return true; // Success
  }
};

const safeUser = new Proxy(user, validator);

safeUser.age = 30; // Works
// safeUser.age = '30'; // Throws TypeError

codeExample2.code:
function* createIdGenerator() {
  let id = 100;
  while (true) {
    yield `USER_${id++}`;
  }
}

const gen = createIdGenerator();

console.log(gen.next().value); // USER_100
console.log(gen.next().value); // USER_101
console.log(gen.next().value); // USER_102

// The loop never crashes because it only runs when gen.next() is called.
